package workerpool

import (
	"sync"
)

// Job represents a unit of work.
type Job struct {
	ID   int
	Data string
}

// Result represents the output of a processed job.
type Result struct {
	JobID  int
	Output string
}

// ProcessFunc is the function applied to each job.
type ProcessFunc func(Job) Result

// Pool manages a pool of workers.
type Pool struct {
	numWorkers int
	processFn  ProcessFunc
}

// New creates a new worker pool.
func New(numWorkers int, fn ProcessFunc) *Pool {
	return &Pool{numWorkers: numWorkers, processFn: fn}
}

// Run starts workers, processes all jobs, and returns results.
func (p *Pool) Run(jobs []Job) []Result {
	jobCh := make(chan Job, len(jobs))
	resCh := make(chan Result, len(jobs))

	var wg sync.WaitGroup
	for i := 0; i < p.numWorkers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for job := range jobCh {
				resCh <- p.processFn(job)
			}
		}()
	}

	for _, job := range jobs {
		jobCh <- job
	}
	close(jobCh)

	go func() {
		wg.Wait()
		close(resCh)
	}()

	var results []Result
	for r := range resCh {
		results = append(results, r)
	}
	return results
}

package main

import (
	"fmt"

	"goworker/pkg/workerpool"
)

func main() {
	pool := workerpool.New(4, func(job workerpool.Job) workerpool.Result {
		return workerpool.Result{
			JobID:  job.ID,
			Output: fmt.Sprintf("processed: %s", job.Data),
		}
	})

	jobs := make([]workerpool.Job, 5)
	for i := 0; i < 5; i++ {
		jobs[i] = workerpool.Job{ID: i, Data: fmt.Sprintf("task-%d", i)}
	}

	results := pool.Run(jobs)
	for _, r := range results {
		fmt.Println(r.Output)
	}
}
